/// <summary>
///
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tableNum(MainAccount),_formControl);

    Query                   query = new Query();
    QueryBuildDataSource    queryBuildDataSource;
    QueryBuildRange         queryBuildRange;
    queryBuildDataSource = query.addDataSource(tableNum(MainAccount));
    queryBuildRange      = queryBuildDataSource.addRange(fieldNum(MainAccount,Ledgerchartofaccounts));

    LegalEntity legalEntity = CompanyInfo::find().RecId;
    Ledger ledger = Ledger::findByLegalEntity(legalEntity);

    queryBuildRange.value(queryValue(ledger.ChartOfAccounts));

    sysTableLookup.addLookupfield(fieldNum(MainAccount,MainaccountId));
    sysTableLookup.addLookupfield(fieldNum(MainAccount,Name));
    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

