/// <returns></returns>
public boolean modified()
{
    boolean ret;

    ret = super();

    ETGACFParameters.MainAccountForGeneralJournal = this.text();
    ETGACFParameters.write();

    return ret;
}

/// <summary>
///
/// </summary>
public void lookup()
{
    super();
    Query query = new Query();
    QueryBuildDataSource    queryBuildDataSource;
    QueryBuildRange         queryBuildRange;


    //To provide the data source
    queryBuildDataSource = query.addDataSource(tableNum(MainAccount));
    queryBuildRange = queryBuildDataSource.addRange(fieldNum(MainAccount,Ledgerchartofaccounts));

    LegalEntity legalEntity = CompanyInfo::find().RecId;
    Ledger ledger = Ledger::findByLegalEntity(legalEntity);

    queryBuildRange.value(queryValue(ledger.ChartOfAccounts));

    //select the fields to display in the lookup
    queryBuildDataSource.addSelectionField(fieldNum(MainAccount,MainaccountId));
    queryBuildDataSource.addSelectionField(fieldNum(MainAccount,Name));

    //providing the constructed query to the multi select lookup
    AccountMultiCtrl = SysLookupMultiSelectCtrl::constructWithQuery(this.formRun(), this, query);

    //The values which are selected in the control setting those values to the multi select control field
    AccountMultiCtrl.set(AccountMultiCtrl.getSelectedFieldValues());
    // CE Rajat Dubey 09/05/2025
}
